// Prendi il primo item dall'input
const ownerData = $input.first().json.owner_data;

// operators[0] è SEMPRE l'owner
const ownerOperator = ownerData.operators?.[0];

// Verifica se ha completato il questionario professionale (soft skills)
// Usa l'optional chaining (?.) per evitare errori se kyc_details è null
const hasProfessionalQuestionnaire = ownerData.kyc_details?.professional_questionnaire ? true : false;

// Costruisci l'oggetto owner
const owner = {
  stakeholder_id: ownerData.user_id,
  name: ownerOperator?.OperatorName || `${ownerData.name} ${ownerData.surname}`,
  email: ownerData.email,
  phone: ownerData.phone || "",
  soft_skills_assessed: hasProfessionalQuestionnaire
};

// Costruisci l'array degli operatori (team)
const teamOperators = (ownerData.operators || [])
  .slice(1) // Salta operators[0] che è l'owner
  .map(op => ({
    // CORREZIONE IMPORTANTE:
    // Se OperatorChatID è null, usa invitation_code, altrimenti stringa vuota.
    // Questo previene l'errore "Cannot read properties of null (reading 'toString')"
    stakeholder_id: op.OperatorChatID ? op.OperatorChatID.toString() : (op.invitation_code || ""),

    name: op.OperatorName,
    role: op.Role || "Operator",
    email: "", // Se non disponibile, lascia vuoto
    soft_skills_assessed: false // Default: operatori non hanno ancora fatto assessment
  }));

// Costruisci la risposta finale
const response = {
  success: true,
  data: {
    owner: owner,
    operators: teamOperators,
    operators_count: teamOperators.length
  }
};

// Ritorna come array per N8N
return [response];

// Prendi il primo item dall'input
const stakeholder = $input.first().json.stakeholder;

// Estrai dati base
const identity = stakeholder.identity || {};
const professional = stakeholder.professional_profile || {};
const behavioral = stakeholder.behavioral_profile || {};
const commercial = stakeholder.commercial_profile || {};
const metadata = stakeholder.metadata || {};

// Determina se è owner o operator
const isOwner = metadata.stakeholder_type === "MANAGER" || 
                professional.role === "owner_manager";

// Costruisci stakeholder_id
const ownerRef = stakeholder.owner_data_ref || {};
const stakeholderId = `${ownerRef.vat_number}-${ownerRef.chat_id}`;

// 🔥 ESTRAI SOFT SKILLS CON EVALUATION COMPLETA
const softSkillsModules = professional.soft_skills_modules || {};
const completedModules = Object.entries(softSkillsModules)
  .filter(([_, module]) => module.completed)
  .map(([moduleName, module]) => ({
    module: moduleName,
    completion_date: module.completion_date || module.timestamp || module.date,
    evaluation: module.evaluation || null
  }))
  .filter(m => m.evaluation !== null);

// Profilo soft skills completo
const softSkillsProfile = professional.soft_skills_complete_profile || {};

// 🔥 ESTRAI LEARNING HISTORY (è già dentro professional.learning_history)
const learningHistory = professional.learning_history || {};
const videosCompleted = learningHistory.videos_completed || [];

// Costruisci la risposta COMPLETA
const response = {
  success: true,
  data: {
    stakeholder_id: stakeholderId,
    name: identity.full_name || "N/A",
    role: isOwner ? "Owner" : (professional.role || "Operator"),
    email: identity.primary_contact?.email || "",
    phone: identity.primary_contact?.phone || "",

    // 🔥 IDENTITY COMPLETA
    identity: {
      stakeholder_type: identity.stakeholder_type || "INDIVIDUAL",
      full_name: identity.full_name || "N/A",
      fiscal_info: identity.fiscal_info || {},
      professional_background: identity.professional_background || {}
    },

    // 🔥 PROFESSIONAL INFO COMPLETA
    professional_info: {
      role: professional.role || "N/A",
      team_size: professional.team_size || "N/A",
      years_experience: professional.years_experience || "N/A",
      hard_skills: professional.hard_skills || [],
      certifications: professional.certifications || "",
      specialization_level: professional.work_preferences?.specialization_level || "N/A",
      client_workflow: professional.work_preferences?.client_workflow || "N/A",
      digital_tools: professional.work_preferences?.digital_tools || [],
      document_management: professional.work_preferences?.document_management || "N/A",
      current_challenges: professional.current_challenges || [],
      main_goal: professional.main_goal || "N/A",
      learning_attitude: professional.learning_attitude || {},
      expertise_areas: behavioral.expertise_areas || [],

      // 🔥 LEARNING HISTORY - PRESO DA professional.learning_history.videos_completed
      learning_history: videosCompleted
    },

    // 🔥 SOFT SKILLS ASSESSMENT CON EVALUATION
    soft_skills_assessment: {
      is_complete: softSkillsProfile.completed || (completedModules.length === 4),
      analyzed_at: softSkillsProfile.stats?.completion_date,
      overall_score: softSkillsProfile.stats?.overall_score,
      modules_completed: completedModules,
      total_modules: 4,
      completed_count: completedModules.length,

      // Se il profilo è completo, includi dettagli
      ...(completedModules.length === 4 && {
        profile_summary: {
          top_skills: softSkillsProfile.strengths || [],
          development_areas: softSkillsProfile.areas_to_improve || [],
          ai_analysis: softSkillsProfile.summary || null
        }
      })
    },

    // 🔥 METADATA COMPLETA
    metadata: {
      status: metadata.status || "ACTIVE",
      stakeholder_type: metadata.stakeholder_type || "OPERATOR",
      created_at: metadata.created_at,
      last_updated: metadata.last_updated || stakeholder.created_at,
      enrichment_date: metadata.enrichment_date,
      intelligence_confidence: metadata.intelligence_confidence || "unknown"
    },

    // 🔥 BEHAVIORAL PROFILE COMPLETO
    behavioral_profile: {
      communication_style: behavioral.communication_style || "N/A",
      expertise_areas: behavioral.expertise_areas || [],
      notes: behavioral.notes || "",
      current_stance: {
        stance_id: behavioral.current_stance?.stance_id || "UNKNOWN",
        set_by: behavioral.current_stance?.set_by,
        set_at: behavioral.current_stance?.set_at,
        rationale: behavioral.current_stance?.rationale
      },
      interaction_summary: behavioral.interaction_summary || {},
      public_reputation: behavioral.public_reputation || {
        sentiment: "neutral",
        credibility_signals: [],
        media_mentions_count: 0,
        trust_score: 0
      }
    },

    // 🔥 COMMERCIAL PROFILE
    commercial_profile: {
      customer_since: commercial.customer_since,
      supplier_since: commercial.supplier_since,
      tags: commercial.tags || [],
      lifetime_value: commercial.lifetime_value || 0,
      total_bookings: commercial.total_bookings || 0
    },

    // 🔥 SOCIAL PROFILES
    social_profiles: identity.social_profiles || {
      facebook: null,
      linkedin: null,
      website: null,
      twitter: null,
      instagram: null
    }
  }
};

return [response];

// ============================================
// N8N CODE NODE - GET OPERATORS LIST
// Esclude Owner (index 0) e operatori senza ChatID
// Output: Array con formato "VAT-CHATID"
// ============================================

const inputData = $input.all();

// L'input è un array con owner_data dentro
const ownerData = inputData[0].json.owner_data || inputData[0].json;

console.log('🔍 Owner VAT:', ownerData.vat_number);

// Controlla che esista l'array operators
if (!ownerData.operators || !Array.isArray(ownerData.operators)) {
    console.log('❌ NO operators array found');
    return [{
        json: {
            total_operators: 0,
            operators_list: []
        }
    }];
}

console.log('📦 Total operators in array:', ownerData.operators.length);

// Filtra operatori: ESCLUDI indice 0 (Owner) e quelli senza ChatID
const activeOperators = ownerData.operators
    .filter((op, index) => {
        // Salta indice 0 (Owner)
        if (index === 0) {
            console.log(`   - ${op.OperatorName} (Owner): SKIPPED ⏭️`);
            return false;
        }

        // Controlla se ha ChatID valorizzato
        const isActive = op.OperatorChatID !== null && 
                         op.OperatorChatID !== "" && 
                         op.OperatorChatID !== undefined;

        console.log(`   - ${op.OperatorName}: ChatID=${op.OperatorChatID} → ${isActive ? '✅' : '❌'}`);

        return isActive;
    });

console.log('✅ Active operators (excluding Owner):', activeOperators.length);

// Crea array con formato VAT-CHATID
const vat = ownerData.vat_number || ownerData.user_id;
const operatorsList = activeOperators.map(op => `${vat}-${op.OperatorChatID}`);

console.log('📋 Final list:', operatorsList);

return [{
    json: {
        total_operators: activeOperators.length,
        operators_list: operatorsList
    }
}];

// ============================================
// N8N CODE NODE - GET TEAM DATA
// Mappa owner_data + operator[] → formato team.html
// ============================================

const inputData = $input.all();
const data = inputData[0].json;

const ownerData = data.owner_data;
const operatorsProfiles = data.operator || []; // Array STAKEHOLDER_PROFILE

console.log('📦 Owner:', ownerData.ragione_sociale);
console.log('📦 Operators profiles found:', operatorsProfiles.length);

// ==========================================
// 1. OWNER INFO
// ==========================================
const ownerInfo = {
    full_name: `${ownerData.name} ${ownerData.surname}`.trim() || ownerData.ragione_sociale
};

// ==========================================
// 2. OPERATORS (da owner_data.operators + operator[])
// ==========================================
const operatorsFromOwnerData = ownerData.operators || [];

// Filtra: escludi index 0 (Owner) e quelli senza ChatID
const activeOperatorsBase = operatorsFromOwnerData
    .filter((op, index) => {
        if (index === 0) {
            console.log(`   ⏭️ SKIP Owner: ${op.OperatorName}`);
            return false;
        }

        const hasChat = op.OperatorChatID !== null && 
                        op.OperatorChatID !== "" && 
                        op.OperatorChatID !== undefined;

        console.log(`   ${hasChat ? '✅' : '❌'} ${op.OperatorName} (ChatID: ${op.OperatorChatID})`);
        return hasChat;
    });

console.log('✅ Active operators:', activeOperatorsBase.length);

// ==========================================
// 3. ARRICCHISCI CON DATI DA STAKEHOLDER_PROFILE
// ==========================================
const operators = activeOperatorsBase.map(op => {
    const chatId = String(op.OperatorChatID);

    // Cerca profilo corrispondente in operator[]
    const profile = operatorsProfiles.find(p => 
        p.system_access?.telegram_chat_id === chatId
    );

    let operatorData = {
        operator_id: chatId,
        name: op.OperatorName,
        role: op.Role || 'Operatore',
        has_assessment: false
    };

    // Se esiste profilo stakeholder, arricchisci
    if (profile) {
        console.log(`   🔗 Linked profile for ${op.OperatorName}`);

        operatorData = {
            operator_id: chatId,
            name: profile.identity?.full_name || op.OperatorName,
            role: profile.identity?.professional_background?.current_role || op.Role || 'Operatore',
            has_assessment: profile.professional_profile?.soft_skills_complete_profile === true,
            email: profile.identity?.primary_contact?.email || null,
            phone: profile.identity?.primary_contact?.phone || null,
            years_experience: profile.identity?.professional_background?.years_experience || null,
            education: profile.identity?.professional_background?.education || null,
            hard_skills: profile.professional_profile?.hard_skills || [],
            certifications: profile.professional_profile?.certifications || null
        };
    } else {
        console.log(`   ⚠️ No profile found for ${op.OperatorName}`);
    }

    return operatorData;
});

console.log('📋 Final operators list:', operators.length);

// ==========================================
// 4. RESPONSE
// ==========================================
return [{
    json: {
        success: true,
        owner_data: ownerInfo,
        operators: operators
    }
}];
